import pytest
from <helper_fn> import api_client, get_audit_events

INT32_MAX = 2147483647

def test_breakglass_max_boundary_patient_id(<fixture>_clinician_token):
    payload = {
        "patient_id": INT32_MAX,
        "reason": "cardiac_arrest",
        "emergency": True
    }
    resp = api_client.post(
        "/BreakGlass",
        json=payload,
        headers={"Authorization": f"Bearer {<fixture>_clinician_token}"}
    )
    assert resp.status_code in (404, 422), (
        f"Expected 404 or 422 for boundary patient_id {INT32_MAX}, got {resp.status_code}"
    )
    body = resp.json()
    assert "error" in body
    assert body.get("access_granted", False) is False
